{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires distinguishing between the absolute binding energy and the energy level relative to the band edge, then applying the Rydberg scaling law.",
  "helpers": [
    {
      "label": "helper_1",
      "instructions": "Determine the exciton Rydberg constant (Ry*) by calculating the binding energy of the 1s state. Explicitly define the binding energy as the difference between the band gap and the 1s peak energy, and clarify whether the Rydberg constant is treated as a positive magnitude or a negative energy level relative to the conduction band edge."
    },
    {
      "label": "helper_2",
      "instructions": "Using the Rydberg constant (Ry*) derived in the first step, calculate the energy level for the n = 3 state. Apply the formula E_n = -Ry*/n^2. Ensure the final value reflects the correct sign convention relative to the band gap threshold as specified by the problem's requirement for sign sensitivity."
    }
  ],
  "synthesis_brief": "Combine the calculated Rydberg constant from helper 1 with the n=3 scaling factor from helper 2 to provide the final energy value, ensuring the sign correctly represents the energy level relative to the band edge."
}

